export const DOMAINS = [{"code":"RG","name":"Role Governance","color":"#185FA5","controls":[{"id":"RG-001","text":"Documented role definition exists before sourcing begins","level":"MUST","tier":1,"definition":"A written document describing the role must be completed and approved before any candidate is reviewed or sourced. This is the internal specification, not the job posting.","example":"Role Definition Worksheet completed by hiring manager with timestamp predating first candidate screen. If first resume reviewed March 5 and definition dated March 8, this fails.","remediation":"Create a Role Definition template. Add an ATS gate blocking sourcing until definition uploaded with timestamp. Train hiring managers to complete before opening any req."},{"id":"RG-002","text":"Role definitions specify business outcomes, not only tasks","level":"MUST","tier":1,"definition":"The definition describes what the person will deliver or change, not activities they perform. Outcomes are measurable results; tasks are activities.","example":"Fails: 'Manage team, attend standups, write PRDs.' Passes: 'Reduce production incidents by 40% in 12 months. Owns architecture tradeoff decisions.'","remediation":"Convert task statements to outcomes: 'What result does this produce?' Provide before/after examples. Reject definitions with only task lists."},{"id":"RG-003","text":"Required vs. learnable capabilities are distinguished","level":"MUST","tier":2,"definition":"The definition separates capabilities required at hire from those developed post-hire. Prevents inflated requirements that screen out qualified candidates.","example":"Required: 'Led teams of 20+ through platform migration.' Learnable: 'Company deployment pipeline.' If all listed as 'required,' fails.","remediation":"Add 'Required at Hire' and 'Learnable Post-Hire' sections. For each capability: 'Would you reject someone strong on everything else?' If no, move to Learnable."},{"id":"RG-004","text":"Decision rights and accountability boundaries specified","level":"MUST","tier":2,"definition":"States what decisions this role makes unilaterally, with consultation, or with approval, and where accountability starts and stops.","example":"'Makes implementation decisions independently. Escalates architecture to Staff+. Budget up to $200K.' No mention of decisions = fails.","remediation":"Add Decision Rights section: Decides Independently / With Consultation / Requires Approval. Include budget authority. Ask: 'Most consequential decision in 90 days?'"},{"id":"RG-005","text":"Scope indicators included","level":"SHOULD","tier":3,"definition":"Quantifies operational scope: reports, budget, cross-functional exposure, ambiguity level, stakeholder complexity.","example":"'8 direct, 35 indirect across 3 time zones. $2M budget. Board exposure. High ambiguity.'","remediation":"Add Scope Indicators: headcount, budget, geographic span, stakeholder exposure, ambiguity rating. Feed into Compensable Factor Analysis."},{"id":"RG-006","text":"Role definitions validated by someone other than hiring manager","level":"SHOULD","tier":3,"definition":"Before sourcing, at least one non-hiring-manager reviews the definition for completeness and alignment.","example":"Peer or HRBP reviews and signs off with name and date. Straight to posting with no review = fails.","remediation":"Add Validator field requiring second signature before req opens. Default: HRBP for IC, skip-level for manager+. Build into workflow."},{"id":"RG-007","text":"Role taxonomy links definitions to compensation and career levels","level":"SHOULD","tier":3,"definition":"Structured mapping connects role definitions to compensation bands, career levels, and capability maps.","example":"'Senior Backend Engineer = IC4 = Band 7 = $150-190K. Factor profile: 3/4/3/3/4.'","remediation":"Build taxonomy mapping titles to career level, comp band, factor profile. Start with 10 most-hired roles. Expand in 6 months."},{"id":"RG-008","text":"Role definition quality scored and measured","level":"MAY","tier":4,"definition":"Organization measures definition quality: specificity, clarity, completeness, strategic alignment.","example":"Each scored: Outcome specificity (1-5), Decision clarity (1-5). Below threshold sent back.","remediation":"Create quality rubric. HR reviews before approving. Track scores by manager. Coach below-threshold."},{"id":"RG-009","text":"Periodic audits compare definitions to actual execution","level":"MAY","tier":5,"definition":"Reviews compare what definition says vs. what person does. Detects definition drift.","example":"Definition says 'owns architecture' but person reports all decisions go through committee. Updated.","remediation":"Annual audits for sample positions. Compare actual work to definition. Flag drift >20% for update and comp review."}]},{"code":"EI","name":"Evaluation Integrity","color":"#0F6E56","controls":[{"id":"EI-001","text":"Evaluation criteria derived from role definition before assessment","level":"MUST","tier":1,"definition":"Before any candidate evaluated, criteria documented and derived from role definition. Criteria created after seeing candidates fail.","example":"Role says 'reduce incidents 40%.' Criteria: 'reliability engineering at scale.' Dated before first interview.","remediation":"Extract 4-6 criteria from role definition. Document in Evaluation Criteria form. Lock with timestamp. Distribute before any screen."},{"id":"EI-002","text":"Every candidate evaluated with same criteria and methods","level":"MUST","tier":1,"definition":"All candidates get identical steps, competencies, scoring. No different process regardless of pipeline source.","example":"Five candidates all do same behavioral + design exercise, same rubric. Referral skips exercise = fails.","remediation":"Standard evaluation sequence per role level. Document. Train: no step skipped. ATS flags incomplete sequences."},{"id":"EI-003","text":"Evaluation assesses capabilities, not solely proxies","level":"MUST","tier":2,"definition":"Measures what candidate can do, not titles, company names, years, or credentials.","example":"Passes: 'Demonstrated scaling from 100K to 10M transactions.' Fails: '12 years at Google, MS from Stanford.'","remediation":"Review questions. Flag proxy-based. Replace with behavioral questions about what candidate did. Train on proxy vs. capability."},{"id":"EI-004","text":"Evaluators document rationale for each score","level":"MUST","tier":2,"definition":"Every evaluator writes reasoning per score, referencing criteria and citing evidence. Score without rationale fails.","example":"'System design: 4/5. Redesigned pipeline for 50x load, queue architecture decisions.' Just 'strong, recommend' = fails.","remediation":"Scorecards require text per criterion that can't be blank. Prompt: 'What evidence supports this score?' Reject blank. Show examples."},{"id":"EI-005","text":"Evaluations include behavioral or situational assessments","level":"SHOULD","tier":3,"definition":"At least one method reveals how candidate operates under role-relevant conditions.","example":"Case with incomplete data, or work sample simulating real challenges. Resume screen alone = fails.","remediation":"Design one structured assessment per role level: case, work sample, or simulation from role definition. Document rubric. Pilot internally."},{"id":"EI-006","text":"Evaluators calibrated targeting .70+ inter-rater reliability","level":"SHOULD","tier":3,"definition":"Measures whether evaluators give similar scores to similar performance. .70+ target.","example":"Three evaluators score same recorded interview. One consistently 1 point higher, recalibrated. Quarterly.","remediation":"Record 3-5 interviews. All evaluators score independently. Calculate reliability. Below .70: calibration sessions. Repeat quarterly."},{"id":"EI-010","text":"Evaluation methods demonstrate construct validity","level":"SHOULD","tier":3,"definition":"Documentation shows each method actually measures the capability it claims to. Correlation for unrelated reasons = invalid.","example":"Design exercise validity brief: designed from role challenges, correlates with on-the-job reviews, known bias toward free time.","remediation":"One-page validity brief per method: what measured, evidence, limitations. No evidence = research, study, or replace."},{"id":"EI-011","text":"Evaluator cognitive load and fatigue managed","level":"SHOULD","tier":3,"definition":"Limits evaluations per day and ensures breaks. Quality degrades with fatigue.","example":"Max 4/day, 15-min breaks, no evaluations after 4:30 PM. Six back-to-back = fails.","remediation":"Scheduling rules: max 4/day, 15-min buffer, no late-day. Exceptions documented and flagged for calibration."},{"id":"EI-007","text":"Structured debriefs: evidence before overall assessments","level":"MAY","tier":4,"definition":"Per-criterion evidence presented before hire/no-hire recommendations. Prevents anchoring.","example":"Evidence per criterion first. No 'I think we should hire' until done. 'What does everyone think?' = fails.","remediation":"Debrief Protocol: verify scorecards, criterion-by-criterion evidence, no recs until done, calibrate, decide. Post in every room."},{"id":"EI-008","text":"Validated psychometric instruments supplement structured evaluation","level":"MAY","tier":4,"definition":"Validated psychometric tools (personality, cognitive ability, situational judgment) may supplement but not replace structured evaluation. Tools must have published validity evidence for the relevant role type.","example":"Organization uses a validated situational judgment test for manager roles alongside structured behavioral interviews. The SJT has published validity data for management selection. Using an unvalidated 'culture fit' quiz = fails.","remediation":"If using psychometrics, verify: (1) published validity for this role type, (2) no adverse impact or documented mitigation, (3) used as supplement only, never sole signal. If current tools lack validity evidence, either find it or discontinue use."},{"id":"EI-012","text":"Evaluation environments assessed for stereotype threat","level":"MAY","tier":4,"definition":"Reviews whether conditions disadvantage candidates based on identity characteristics unrelated to role.","example":"All-male interviewers, whiteboard only. Fix: diverse panels, multiple formats, inclusive environment.","remediation":"Audit: interviewer demographics, formats, language. Implement diverse panels, multiple formats, inclusive communications."},{"id":"EI-013","text":"Impression management controls in evaluation design","level":"MAY","tier":4,"definition":"Evaluation methods reduce candidates' ability to substitute rehearsed narratives for demonstrated capability. Uses behavioral anchoring, work samples, and simulations rather than self-report.","example":"Instead of 'tell me about your leadership style' (rehearsable), use 'walk me through the last time you had to deliver bad news to your team, including what you said and how they responded' (behavioral, harder to fake). Or a work sample where the candidate solves a real problem.","remediation":"Review evaluation questions for rehearsability. Replace abstract self-report questions with behavioral probes anchored to specific past events. Add at least one work sample or simulation per evaluation sequence that requires demonstrating capability rather than describing it."},{"id":"EI-009","text":"Post-hire validation compares evaluation to outcomes","level":"MAY","tier":5,"definition":"Tracks whether high scores predict strong performance using signal detection analysis.","example":"12-month study: Criterion 3 lowest validity, Criterion 1 highest. Reweighted.","remediation":"Validation study: scores vs. 6/12-month performance. Correlate each criterion. Adjust weights from predictive data."}]},{"code":"DG","name":"Decision Governance","color":"#534AB7","controls":[{"id":"DG-001","text":"Every hiring decision documented with selection rationale, including AI-assisted decision modifications","level":"MUST","tier":1,"definition":"Written record explains why candidate chosen. For AI-assisted decisions, documentation must specify what the AI recommended, what the human reviewer changed (if anything), and the rationale for accepting or overriding. Standalone document, not email/Slack. Primary audit artifact.","example":"Decision Rationale Form: candidate, date, decision-maker, scores, evidence, comparison. Slack 'let's go with A' = fails.","remediation":"Decision Rationale form required before offer. Include: decision-maker, date, scores, evidence, comparison. HR checks completeness before approval."},{"id":"DG-002","text":"Rationale references criteria and is contemporaneous","level":"MUST","tier":1,"definition":"References evaluation criteria and documented at or near decision time. Late rationale = post-decision rationalization.","example":"Passes: criteria scores + evidence within 24 hours. Fails: 2 weeks later, 'great energy,' no criteria.","remediation":"24-hour deadline after decision meeting. Auto-remind. >72 hours = flagged. Must reference specific criteria and scores."},{"id":"DG-003","text":"Decision authority defined: who approves, who participates","level":"MUST","tier":2,"definition":"Documented matrix: final authority by role level, participation model. Decision-maker named.","example":"'IC: manager decides. Manager+: skip-level approves.' No identifiable decider = fails.","remediation":"Create Decision Authority Matrix: levels x roles. Publish. Each rationale form names the decider, matched to matrix authority."},{"id":"DG-004","text":"Decision-makers disclose conflicts of interest","level":"SHOULD","tier":3,"definition":"Disclose personal/professional relationships or interests before participating in evaluation.","example":"'Candidate B is former colleague.' Documented. Undiscovered after hire = fails.","remediation":"COI question at evaluator briefing. Document all disclosures. Standing question every debrief."},{"id":"DG-005","text":"Mechanisms detect scoring inconsistencies and bias","level":"SHOULD","tier":3,"definition":"Monitors scoring for bias: demographic patterns, anchoring, halo/horn, affinity, contrast, primacy/recency.","example":"Quarterly: Evaluator X scores women 0.8 lower on leadership. Evaluator Y: first candidate always higher. Flagged.","remediation":"Quarterly analysis: scores by demographic, time, sequence. Flag >0.5 systematic deviation. Route to calibration."},{"id":"DG-006","text":"Rejection decisions include substantive rationale","level":"SHOULD","tier":3,"definition":"Rejected qualified candidates get rationale naming unmet criteria. 'Not the best fit' fails.","example":"Passes: 'Gap on org transformation: same-team examples only.' Fails: 'Different direction.'","remediation":"Rationale form for rejections. Final-stage: name unmet criterion + evidence. Train with examples."},{"id":"DG-007","text":"Structured debrief: individual scores before group discussion","level":"SHOULD","tier":3,"definition":"Scorecards submitted before debrief. Prevents loudest voice from anchoring the group.","example":"Scorecards by 1 PM, debrief at 2 PM, criterion-by-criterion. Filled during debrief = fails.","remediation":"Deadline 2 hours before debrief. Calendar: 'Submit scorecard first.' Facilitator verifies before starting."},{"id":"DG-009","text":"Post-decision rationalization detection","level":"SHOULD","tier":3,"definition":"Monitors for late documentation, no criteria reference, contradicts scores, vague language.","example":"Auto-flag: rationale 7 days after decision. Manual flag: 'culture alignment' with no criteria. Both reviewed.","remediation":"Automated flags: >48 hours = flag. Text scan for 'culture fit/gut feel' = flag. Route to manager's manager."},{"id":"DG-008","text":"Decision review boards for senior/high-impact hires","level":"MAY","tier":4,"definition":"Board examines rationale, evidence, and process before offer for exec/high-comp hires.","example":"Director+ reviewed by CHRO + VP + independent exec. Gaps = pause.","remediation":"Talent Review Board for Director+. Checklist: definition, criteria, scorecards, rationale, comp. Before offer."},{"id":"DG-010","text":"Decision quality metrics published","level":"MAY","tier":5,"definition":"Tracks quality: time-to-productivity, score-to-performance correlation, retention by evaluator.","example":"'Q4 hires productive in 4.2 months vs 5.8 Q2. Manager X: 90% retention vs 78% org.'","remediation":"Define metrics: retention, productivity, correlation. Baseline 12 months. Report quarterly. Refine from data."},{"id":"DG-011","text":"Governance failure incident response process defined and tested","level":"MUST","tier":2,"definition":"When a governance control fails (biased decision detected, AI tool produces disparate outcomes, reviewer found rubber-stamping, records missing), the organization has a defined process for incident response: identification, containment, root cause analysis, remediation, affected-party notification where required, and documentation of corrective action. The process must be tested at least annually.","example":"Quarterly review discovers that a screening AI rejected 40% more candidates from one demographic. Incident response triggered within 24 hours: tool suspended, affected candidates re-evaluated, root cause traced to training data bias, vendor notified, corrective action documented, and affected candidates notified within 30 days. Organization without incident response discovers the same issue during litigation.","remediation":"Define incident response protocol: (1) Identification criteria and reporting channels, (2) Containment steps (suspend tool/process), (3) Root cause analysis within 72 hours, (4) Remediation plan with timeline, (5) Affected-party notification where legally required or ethically appropriate, (6) Post-incident review and control updates. Test annually with tabletop exercise. Name incident response owner."}]},{"code":"AG","name":"AI Governance","color":"#993C1D","controls":[{"id":"AG-001","text":"Inventory of all automated decision tools maintained","level":"MUST","tier":1,"definition":"Documented list of every tool that filters, scores, ranks, or recommends candidates or compensation.","example":"Inventory: (1) Greenhouse auto-screen, (2) HireVue, (3) Radford comp. Each: name, vendor, function, owner. Missing tool = fails.","remediation":"Survey every hiring team: 'What software touches candidate data?' List all. Document per tool. Review annually."},{"id":"AG-002","text":"No ADT sole decision-maker; human with demonstrated override behavior required","level":"MUST","tier":1,"definition":"Human with context and authority reviews every consequential output before it takes effect. Presence alone is insufficient: the reviewer must demonstrate substantive engagement, not nominal approval. Batch 'approve all' = fails. 100% acceptance rate without documented rationale = fails.","example":"Recruiter reviews advances + 10% of rejections. Overrides 3 with documented reasoning. Override rate tracked quarterly. 0% override rate over 90 days triggers review. Auto-reject without review = fails.","remediation":"Define Human Review Point per ADT. Require 10% rejection sample review. Log every review and override. Track override rates by reviewer. Flag reviewers with 0% override rates for substantive engagement assessment (see AG-012)."},{"id":"AG-003","text":"Can explain in plain language how each ADT works","level":"MUST","tier":2,"definition":"For every tool: what data in, what rules applied, what comes out. 'Vendor proprietary algorithm' = fails.","example":"Passes: 'Matches 12 keywords weighted by section. Above 60% advances.' Fails: 'AI finds best candidates.'","remediation":"Per ADT, plain-language doc: data, logic, output. If vendor can't explain, request docs or consider replacing."},{"id":"AG-004","text":"ADTs tested for disparate impact before deployment and regularly","level":"MUST","tier":2,"definition":"Before launch and annually: test if tool screens out protected classes disproportionately. Four-fifths rule.","example":"Men 35%, women 22%. 63% < 80% threshold. Over-weights continuous employment. Adjusted. Never tested = fails.","remediation":"Pre-deployment analysis: rates by gender, race, age. Four-fifths rule. Impact found: investigate features, adjust, retest. Annual."},{"id":"AG-005","text":"Candidates told when ADTs used","level":"SHOULD","tier":3,"definition":"Candidates informed when automated tools are involved, with general description.","example":"'Application may be reviewed by automated screening. All recommendations reviewed by human recruiter.'","remediation":"Disclosure in application email, careers page, new ADT stages. Describe function. Confirm human review. Legal review."},{"id":"AG-006","text":"ADT outputs auditable: can reconstruct individual decisions","level":"SHOULD","tier":3,"definition":"For any candidate, explain specifically why tool advanced or rejected them.","example":"'Score 42/100. Threshold 60. Missing: distributed systems, API design.' Can't produce = fails.","remediation":"Verify individual logs per ADT. Test: explanation for 5 candidates. Can't = vendor fix or flag as risk."},{"id":"AG-007","text":"Accountable owner designated for each ADT","level":"SHOULD","tier":3,"definition":"Named person (not department) responsible for monitoring, testing, compliance.","example":"'Owner: Sarah Chen, Dir Talent Ops.' 'HR Department' without name = partial.","remediation":"Named owner per ADT. Responsibilities: tests, docs, audit coordination. Review on personnel changes."},{"id":"AG-008","text":"A/B testing compares ADT vs. human accuracy","level":"MAY","tier":4,"definition":"Both ADT and humans independently assess same candidates; compare against outcomes.","example":"3 months parallel. After 6 months compare to on-the-job performance.","remediation":"Parallel evaluation study. Both assess same candidates. Compare to 6-12 month outcomes. Calibrate thresholds."},{"id":"AG-009","text":"Adversarial testing identifies failure modes","level":"MAY","tier":4,"definition":"Deliberately try to break tools: keyword stuffing, synthetic profiles, demographic bias tests.","example":"Identical resumes, different names. Keyword stuffing. Unusual format + qualified.","remediation":"Adversarial suite: demographics, stuffing, format, unqualified+keywords. Run annually and after updates."},{"id":"AG-010","text":"ADT performance data contributed to benchmarking","level":"MAY","tier":5,"definition":"Anonymized accuracy, bias results, override rates shared with industry groups.","example":"'False rejection 12%. Override 8%. Impact improved 0.63 to 0.81.'","remediation":"Join industry groups. Anonymized data packages annually."},{"id":"AG-011","text":"Workforce trust profiles assessed before AI deployment in high-stakes decisions","level":"SHOULD","tier":3,"definition":"Before deploying AI decision tools in consequential contexts (hiring, evaluation, compensation), the organization assesses the trust disposition of the workforce that will use them. Trust is a trait, not a state: it is not moved by design interventions and varies significantly across individuals. Organizations that deploy without profiling cannot distinguish substantive oversight from deference.","example":"Pre-deployment assessment identifies that 12% of hiring managers exhibit blind trust profiles. These individuals receive additional training and paired review requirements before using AI screening tools. Organization without profiling discovers post-litigation that reviewers had 100% acceptance rates.","remediation":"Administer validated trust profile assessment to all personnel who will interact with AI decision tools. Classify into profiles (blind trust, conflicted, ambivalent, skeptical). Tailor governance controls by profile. Reassess annually and after significant AI tool changes. Reference: Malefyt (2026), HCCS-RS-001."},{"id":"AG-012","text":"Substantive human oversight distinguished from nominal oversight","level":"MUST","tier":2,"definition":"The organization demonstrates that human review of AI outputs involves genuine judgment, not rubber-stamping. Substantive oversight requires evidence that the reviewer independently evaluated the output, considered alternatives, and can articulate their reasoning. Nominal oversight, where the reviewer approves without meaningful engagement, does not satisfy human-in-the-loop requirements and must be detected and remediated.","example":"Substantive: Reviewer modifies 3 of 15 AI screening recommendations with documented rationale. Override rate: 20%. Nominal: Reviewer approves all 47 AI recommendations in 12 minutes with no modifications and no documented rationale. Override rate: 0%. The second pattern triggers AG-013 monitoring.","remediation":"Define substantive oversight criteria: minimum review time per decision, required documentation of independent assessment, tracked modification rates. Implement automated detection of nominal patterns (0% override, below-threshold review time, no rationale documented). Route flagged reviewers to calibration. Reference: Malefyt (2026), HCCS-RS-001."},{"id":"AG-013","text":"Deference risk monitored in AI-assisted decision pipelines","level":"SHOULD","tier":3,"definition":"Ongoing monitoring detects when human reviewers defer to AI outputs without critical engagement. Deference risk is concentrated in specific trust profiles (blind trusters, 9% of population in reference study) and can be predicted by prior AI usage patterns. Monitoring is not punitive; it is protective. Undetected deference transfers de facto decision authority to the AI system without organizational awareness or consent.","example":"Quarterly analysis: Reviewer A has 0% override rate across 200 AI-screened candidates. Reviewer B has 18% override rate with documented rationale for each. Reviewer A is flagged for trust profile assessment and paired review. Pattern detected before audit, not during.","remediation":"Track override rates, review times, and rationale completeness by reviewer. Flag systematic deference patterns (0-2% override rate over 90+ days, below-threshold review times). Conduct trust profile assessment for flagged reviewers. Implement paired review for high-deference individuals. Report deference metrics alongside ADT performance metrics. Reference: Malefyt (2026), HCCS-RS-001."},{"id":"AG-014","text":"Third-party vendors in the decision pipeline subject to governance requirements","level":"SHOULD","tier":3,"definition":"When third-party services contribute to consequential decisions (background check providers, credentialing agencies, credit bureaus, clinical decision support vendors, AI screening services), the organization extends governance requirements to those vendors. Vendor outputs are treated as inputs to the decision, not as decisions themselves. The organization retains accountability for the final decision regardless of vendor involvement.","example":"Background check vendor flags a candidate based on a common-name match. Organization has a defined process: vendor results are reviewed by a trained human before any adverse action. Vendor contract requires explainability of results, annual disparate impact testing, and incident notification. Organization that auto-rejects based on vendor output without review = fails.","remediation":"Inventory all third-party services in the decision pipeline. For each: (1) Document what the vendor provides and how it influences decisions, (2) Require vendor to provide explainability and disparate impact testing data, (3) Define human review requirements for vendor outputs before adverse action, (4) Include governance requirements in vendor contracts, (5) Annual vendor governance review. Treat vendor outputs as recommendations, not decisions."}]},{"code":"PI","name":"Process Integrity","color":"#854F0B","controls":[{"id":"PI-001","text":"Every externally posted role is genuinely open","level":"MUST","tier":1,"definition":"If posted externally, external candidates must have real opportunity to be selected. Not predetermined.","example":"5 external + 2 internal evaluated identically, external selected = passes. Manager told internal 'this is yours' = fails.","remediation":"Process Classification before posting. Manager selects: Open/Internal-Preference/Restricted. Open = attests no promise. Pattern detected by PI-004."},{"id":"PI-002","text":"Internal-preference processes documented before posting","level":"MUST","tier":2,"definition":"If internal candidate preferred, document before posting. Failure is not disclosing, not having preference.","example":"Before posting: 'Internal-Preference. Jane Smith. Rationale: promotion. External evaluated on identical criteria.'","remediation":"Classification Record before req approval. Name candidate, rationale, confirm identical criteria. Timestamp before posting."},{"id":"PI-003","text":"All candidates past screening evaluated identically","level":"MUST","tier":2,"definition":"Same criteria, methods, rigor, timeline regardless of source. No shortcuts for referrals.","example":"Referred + cold-apply both complete same 4-stage process = passes. CEO referral gets 30-min chat = fails.","remediation":"Standard sequence per level. ATS tracks completion. Flag skipped stages. No exceptions for referral source."},{"id":"PI-004","text":"Internal-preference hire ratios tracked by department","level":"SHOULD","tier":3,"definition":"Track percentage from internal-preference vs. open, by department and level.","example":"'Eng IC: 70% open, 30% internal. Eng Manager: 40% open.' 90%+ internal = review.","remediation":"ATS report: classification per hire by department/level. Monthly to HR, quarterly to exec. >80% internal = review."},{"id":"PI-005","text":"Timelines communicated; deviations shared proactively","level":"SHOULD","tier":3,"definition":"Candidates get estimates upfront. Material deviations communicated.","example":"'Process 3-4 weeks, update each stage.' Delayed: 'Extended to April 15.' Silence 8 weeks = fails.","remediation":"Standardize: ack within 3 days, status per stage, timeline at screen, proactive notice if >5 day deviation. Templates + ATS."},{"id":"PI-006","text":"Final-stage candidates get substantive feedback","level":"SHOULD","tier":3,"definition":"Feedback references criteria, identifies specific gaps, delivered by a person.","example":"'Gap: org transformation, same-team examples only.' 'Moving forward with another candidate' = fails.","remediation":"Template: 'Gap was [criterion]: [what missing].' Phone for Director+, personal email for others. Train managers."},{"id":"PI-007","text":"Process audits assess consistency across demographics","level":"MAY","tier":4,"definition":"Check whether time-to-decision, pass-through, rounds are consistent across groups.","example":"White candidates 18 days, Black candidates 26 days. Extra round found. Eliminated.","remediation":"Semi-annual: time-in-stage, pass-through by demographics. >15% variance = investigate. Document actions."},{"id":"PI-008","text":"Anonymized process metrics published","level":"MAY","tier":5,"definition":"Publish open/internal ratios, time-to-decision, feedback rates, satisfaction.","example":"'68% open. 21 days average. 92% feedback. NPS 72.'","remediation":"Annual Transparency Report. Publish on careers page."},{"id":"PI-009","text":"Decision-makers trained in governance framework before participating in consequential decisions","level":"MUST","tier":2,"definition":"All personnel who make, evaluate, or review consequential decisions must complete governance training before participating. Training covers: the applicable HCCS controls, documentation requirements, bias recognition, AI tool oversight responsibilities, and the distinction between substantive and nominal review. Training is not a one-time event; it must be refreshed annually and updated when controls change.","example":"New hiring manager completes 2-hour HCCS governance training before conducting first interview. Training covers: structured evaluation, scorecard documentation, bias types, AI screening review requirements. Certification documented. Annual refresher required. Manager who has never been trained conducting interviews = fails.","remediation":"Develop role-specific training modules: (1) Evaluators: structured assessment, scorecard documentation, bias recognition, (2) Decision-makers: rationale documentation, authority matrix, AI override requirements, (3) AI tool users: substantive oversight, deference risk, trust profiles. Track completion. Block participation in decision processes until training complete. Annual refresher. Update training when controls change."},{"id":"PI-010","text":"Affected parties can challenge consequential decisions through a defined process","level":"SHOULD","tier":3,"definition":"Individuals affected by consequential decisions (applicants, employees, patients, borrowers) have access to a defined process for challenging the decision and receiving a substantive review by a person who was not involved in the original decision. The challenge process must be communicated to affected parties, must have a defined timeline for response, and must result in a documented outcome.","example":"Rejected candidate requests review. Organization has a defined process: request submitted within 14 days, reviewed by an independent evaluator within 10 business days, written response addresses specific concerns and references evaluation criteria. Organization that responds with \"we cannot discuss our process\" or has no challenge mechanism = fails.","remediation":"Define challenge process: (1) How to submit (form, email, portal), (2) Timeline for acknowledgment (3 business days) and response (10 business days), (3) Independent reviewer not involved in original decision, (4) Written response referencing criteria and evidence, (5) Escalation path if dissatisfied. Communicate to all affected parties at decision notification. Document all challenges and outcomes for pattern analysis."}]},{"code":"CG","name":"Compensation Governance","color":"#3B6D11","controls":[{"id":"CG-001","text":"Compensation uses compensable factors, not title or salary history","level":"MUST","tier":1,"definition":"Pay from role scope analysis, not title matching, salary history, or predecessor pay.","example":"Factor analysis: Authority 5, Complexity 5. Range $280-340K = passes. 'Radford says $310K, candidate makes $280K' = fails.","remediation":"Factor Analysis template. Complete before pay. Remove salary history from apps. Factor analysis required before market data."},{"id":"CG-002","text":"Five factors: authority, complexity, accountability, impact, expertise","level":"MUST","tier":2,"definition":"Framework uses minimum five factors, each scored 1-5 with rationale.","example":"'Accountability 4/5: owns pipeline end-to-end, regulatory exposure on failure.' Just 'High' = fails.","remediation":"Template: five sections, each with definition, 1-5 guide, rationale field. Train. New hires first, backfill in 12 months."},{"id":"CG-003","text":"Rationale connecting factors to pay documented","level":"MUST","tier":2,"definition":"Shows factor range, actual offer, deviation rationale, salary history non-use.","example":"'Range $150-190K. Offer $175K at 65th percentile. Stack expertise justifies above-mid. No salary history.' No doc = fails.","remediation":"Comp Rationale in offer workflow: range, offer, positioning, non-use checkbox. Analyst review before approval."},{"id":"CG-004","text":"Annual scope-to-compensation alignment reviews","level":"SHOULD","tier":3,"definition":"Yearly check whether comp aligns with actual scope, which may have changed.","example":"Hired at Complexity 3. Now owns 3 teams (Complexity 4). Range $190-220K. Adjustment recommended.","remediation":"Annual: managers re-score factors. Compare to hire-date. 1+ point increase = flag for adjustment. Catches scope creep."},{"id":"CG-005","text":"Comp decisions follow same audit trail as hiring","level":"SHOULD","tier":3,"definition":"Same documentation rigor, retention, audit access as hiring decisions.","example":"Every change has Rationale Form, retained 3 years. Changes in HRIS with no doc = fails.","remediation":"Same ER governance for comp. Same forms, system, retention, audit access. Comp is equally consequential."},{"id":"CG-006","text":"Pay equity analysis by demographics, controlling for factors","level":"SHOULD","tier":3,"definition":"Whether equivalent-scope people are paid equivalently regardless of demographics.","example":"Women at equivalent factors paid 97.2% (noise). Sales: 91.4%. Negotiation-driven. Standardize.","remediation":"Equity analysis controlling for factors by gender, race, age. >3% gap = investigate. Common: negotiation, tenure."},{"id":"CG-007","text":"Real-time comp modeling when scope changes","level":"MAY","tier":4,"definition":"System flags scope changes and triggers auto review.","example":"Promoted to tech lead, 5 reports. Auto-generates factor re-analysis request.","remediation":"HRIS triggers: promotion, reporting change, headcount. Auto-generate re-analysis. Continuous vs. annual-only."},{"id":"CG-008","text":"Factor-based benchmarking data contributed","level":"MAY","tier":5,"definition":"Anonymized comp data by factors contributed to surveys.","example":"Factor profile 5/5/5/5/4: $280-340K vs. 3/4/3/3/4: $180-220K. Both VP Eng.","remediation":"Include factor data in survey contributions. Work with vendor. Advocate for factor-based benchmarking."}]},{"code":"ER","name":"Evidence & Records","color":"#993556","controls":[{"id":"ER-001","text":"Contemporaneous records for every decision","level":"MUST","tier":1,"definition":"Created at decision time. Scorecards within 4 hours, rationale within 24 hours, classifications before posting. For AI-assisted decisions, records must distinguish substantive review (human altered or independently validated the output) from pass-through approval (human accepted without modification). 72+ hours = retrospective = fails.","example":"Interview 10 AM, scorecard 12:30 PM = passes. Interview March 5, scorecard March 15 = fails.","remediation":"System deadlines: scorecards lock 4 hours post-interview, rationale locks 48 hours. Auto-remind. Late = flagged."},{"id":"ER-002","text":"Records retained minimum 3 years","level":"MUST","tier":1,"definition":"All records kept 3+ years. Exceeds EEOC (1 year), OFCCP (2 years).","example":"Hire Jan 2026, records until Jan 2029. Auto-purge at 12 months = fails.","remediation":"3-year retention (5 recommended). Disable auto-purge. Departing employee records archived, not deleted."},{"id":"ER-003","text":"Records classified and retrievable within 48 hours","level":"MUST","tier":2,"definition":"Organized by domain, type, date. Auditor requests 'Q3 evaluations' and gets them within 48 hours.","example":"System returns 47 scorecards in 4 hours = passes. 3 weeks across Google Drives = fails.","remediation":"Centralized system. Classification: [Domain]-[Type]-[Date]-[ReqID]. Train. Monthly: retrieve random hire within 1 hour."},{"id":"ER-004","text":"Named accountability for records governance","level":"MUST","tier":2,"definition":"Specific person (not department) accountable for creation, storage, retention, producibility.","example":"'Maria Lopez, Sr HR Ops.' Answer 'HR' without name = partial.","remediation":"Named owner with written responsibilities. Include in performance objectives."},{"id":"ER-005","text":"Records linked to specific HCCS control IDs","level":"SHOULD","tier":3,"definition":"System connects documents to controls they satisfy. Enables targeted audit.","example":"'Scorecard 2847 satisfies EI-002, EI-004, Req-0342.' Search by control ID finds all evidence.","remediation":"Add 'Control IDs' metadata. Tag each document. Manual first, automate later. Enables control-based audit search."},{"id":"ER-006","text":"Access restricted and logged","level":"SHOULD","tier":3,"definition":"Role-based access. Every access logged with timestamp and user.","example":"System logs access. Shared Drive anyone can access = fails.","remediation":"Role-based access: managers own, HRBPs department, audit all. Enable logging. Review quarterly."},{"id":"ER-007","text":"Automated evidence collection at point of decision","level":"MAY","tier":4,"definition":"Records auto-created on decision. No manual form-filling after.","example":"Evaluator clicks submit, system creates timestamped scorecard tagged to controls.","remediation":"Evaluate ATS auto-export. Configure structured export. Can't: Zapier/API on submit."},{"id":"ER-008","text":"Records completeness audits","level":"MAY","tier":4,"definition":"Periodic checks that records exist for every decision that should have one.","example":"'47 hires, 47 definitions (100%), 44 rationale (93.6%). 3 Sales gaps flagged.'","remediation":"Quarterly: all hires vs. records by domain. Coverage by department. Route gaps to managers."},{"id":"ER-009","text":"Tamper-evident storage for high-stakes decisions","level":"MAY","tier":5,"definition":"Executive/sensitive records stored where modifications impossible or leave audit trail.","example":"Director+ in version-controlled system. Edits create versions. Dual-auth deletion.","remediation":"Director+ in immutable system. Version history + restricted deletion. No silent modification."}]}];
